   333→// Tool 10: Enhanced Screenshot Capture
   334→server.addTool({
   335→  name: "screenshot",
   336→  description:
   337→    "Capture a screenshot (full screen, region, or window). Default to full screen if no preference. This will also provide information about the user's screen in order to correctly position mouse clicks and keyboard inputs.",
   338→  parameters: z.object({
   339→    mode: z
   340→      .enum(["full", "region", "window"])
   341→      .default("full")
   342→      .describe("Capture mode: full (entire screen), region, or window"),
   343→    regionX: z
   344→      .number()
   345→      .optional()
   346→      .describe("Region X coordinate (for region mode)"),
   347→    regionY: z
   348→      .number()
   349→      .optional()
   350→      .describe("Region Y coordinate (for region mode)"),
   351→    regionWidth: z
   352→      .number()
   353→      .optional()
   354→      .describe("Region width (for region mode)"),
   355→    regionHeight: z
   356→      .number()
   357→      .optional()
   358→      .describe("Region height (for region mode)"),
   359→    windowName: z.string().optional().describe("Window title (if mode=window)"),
   360→    windowId: z.number().optional().describe("Window ID (if mode=window)"),
   361→  }),
   362→  execute: async ({
   363→    mode,
   364→    regionX,
   365→    regionY,
   366→    regionWidth,
   367→    regionHeight,
   368→    windowName,
   369→    windowId,
   370→  }) => {
   371→    try {
   372→      const filePath = path.join(
   373→        os.tmpdir(),
   374→        `mcp_screenshot_${Date.now()}.png`
   375→      );
   376→
   377→      // Perform the OS-level screencapture
   378→      if (mode === "full") {
   379→        child_process.execSync(`screencapture -x -D1 "${filePath}"`);
   380→      } else if (mode === "region") {
   381→        if (
   382→          regionX === undefined ||
   383→          regionY === undefined ||
   384→          regionWidth === undefined ||
   385→          regionHeight === undefined
   386→        ) {
   387→          throw new Error(
   388→            "Region mode requires regionX, regionY, regionWidth, and regionHeight parameters"
   389→          );
   390→        }
   391→        child_process.execSync(
   392→          `screencapture -x -R${regionX},${regionY},${regionWidth},${regionHeight} "${filePath}"`
   393→        );
   394→      } else if (mode === "window") {
   395→        let targetId = windowId;
   396→        if (!targetId && windowName) {
   397→          const { openWindows } = require("get-windows");
   398→          const allWindows = await openWindows();
   399→          const targetWin = allWindows.find(
   400→            (w: any) => w.title && w.title.includes(windowName)
   401→          );
   402→          if (!targetWin)
   403→            throw new Error(
   404→              `Window containing title "${windowName}" not found`
   405→            );
   406→          targetId = targetWin.id;
   407→        }
   408→        if (!targetId)
   409→          throw new Error(
   410→            "Could not determine target window ID for screenshot."
   411→          );
   412→        child_process.execSync(`screencapture -x -l${targetId} "${filePath}"`);
   413→      }
   414→
   415→      if (!require("fs").existsSync(filePath)) {
   416→        throw new Error(`Screenshot file was not created at ${filePath}`);
   417→      }
   418→
   419→      // Read file and encode as base64 manually
   420→      const fs = require("fs");
   421→      const imageBuffer = fs.readFileSync(filePath);
   422→      const base64Data = imageBuffer.toString("base64");
   423→
   424→      // Clean up temp file
   425→      fs.unlinkSync(filePath);
   426→
   427→      return {
   428→        content: [
   429→          {
   430→            type: "image",
   431→            data: base64Data,
   432→            mimeType: "image/png",
   433→          },
   434→        ],
   435→      };
   436→    } catch (error: any) {
   437→      throw new Error(`Screenshot failed: ${error.message}`);
   438→    }
   439→  },
   440→});
