   607→      targetWindow = await Promise.all(
   608→        windows.map(async (win: any) => ({
   609→          window: win,
   610→          title: await win.getTitle(),
   611→        }))
   612→      ).then(
   613→        (windowsWithTitles) =>
   614→          windowsWithTitles.find((w) => w.title.includes(windowTitle))?.window
   615→      );
   616→
   617→      if (!targetWindow) {
   618→        throw new Error(
   619→          `Window with title containing "${windowTitle}" not found`
   620→        );
   621→      }
   622→    } else {
   623→      targetWindow = await getActiveWindow();
   624→    }
   625→
   626→    const windowName = await targetWindow.getTitle();
   627→
   628→    switch (action) {
   629→      case "focus":
   630→        await targetWindow.focus();
   631→        return `Focused window: "${windowName}"`;
   632→
   633→      case "move":
   634→        if (x === undefined || y === undefined) {
   635→          throw new Error("Move action requires x and y coordinates");
   636→        }
   637→        await targetWindow.move(new Point(x, y));
   638→        return `Moved window "${windowName}" to (${x}, ${y})`;
   639→
   640→      case "resize":
   641→        if (width === undefined || height === undefined) {
   642→          throw new Error("Resize action requires width and height");
   643→        }
   644→        await targetWindow.resize(new Size(width, height));
   645→        return `Resized window "${windowName}" to ${width}x${height}`;
   646→
   647→      case "minimize":
   648→        await targetWindow.minimize();
   649→        return `Minimized window: "${windowName}"`;
   650→
   651→      case "restore":
   652→        await targetWindow.restore();
   653→        return `Restored window: "${windowName}"`;
   654→
   655→      default:
   656→        throw new Error(`Unknown action: ${action}`);
   657→    }
   658→  },
   659→});
   660→
   661→// ============== ADVANCED AUTOMATION TOOLS ==============
   662→
   663→// Tool 17: Wait and Find on Screen
   664→server.addTool({
   665→  name: "waitForImage",
   666→  description: "Wait for an image to appear on screen and return its location.",
   667→  parameters: z.object({
   668→    imagePath: z.string().describe("Path to the template image file"),
   669→    timeoutMs: z.number().default(5000).describe("Timeout in milliseconds"),
   670→    confidence: z
   671→      .number()
   672→      .min(0)
   673→      .max(1)
   674→      .default(0.8)
   675→      .describe("Match confidence (0-1)"),
   676→  }),
   677→  execute: async ({ imagePath, timeoutMs, confidence }) => {
   678→    return `Image matching functionality requires additional setup. Would wait for image "${imagePath}" with confidence ${confidence} for ${timeoutMs}ms.`;
   679→  },
   680→});
   681→
   682→// Tool 18: Sleep/Delay
   683→server.addTool({
   684→  name: "sleep",
   685→  description: "Pause execution for a specified amount of time.",
   686→  parameters: z.object({
   687→    ms: z.number().describe("Time to sleep in milliseconds"),
   688→  }),
   689→  execute: async ({ ms }) => {
   690→    await new Promise((resolve) => setTimeout(resolve, ms));
   691→    return `Slept for ${ms} milliseconds`;
   692→  },
   693→});
   694→
   695→// Tool 19: Complex Mouse Path Movement
   696→server.addTool({
   697→  name: "mouseMovePath",
   698→  description: "Move mouse along a path of coordinates with smooth animation.",
   699→  parameters: z.object({
   700→    path: z
   701→      .array(z.number())
   702→      .describe(
   703→        "Array of coordinates to move through (alternating x,y values: [x1,y1,x2,y2,...])"
   704→      ),
   705→  }),
   706→  execute: async ({ path }) => {
   707→    requireNutjs();
   708→
   709→    // Validate that we have an even number of coordinates
   710→    if (path.length % 2 !== 0) {
   711→      throw new Error(
   712→        "Path array must contain an even number of values (alternating x,y coordinates)"
   713→      );
   714→    }
   715→
   716→    // Convert flat array to Point objects
   717→    const points: any[] = [];
   718→    for (let i = 0; i < path.length; i += 2) {
   719→      points.push(new Point(path[i], path[i + 1]));
   720→    }
   721→
   722→    await mouse.move(points);
   723→    return `Mouse moved along path with ${points.length} points`;
   724→  },
   725→});
   726→
   727→// Tool 20: System Key Combinations
   728→server.addTool({
   729→  name: "systemCommand",
   730→  description:
   731→    "Execute common system key combinations (copy, paste, undo, etc.).",
   732→  parameters: z.object({
   733→    command: z
   734→      .enum([
   735→        "copy",
   736→        "paste",
   737→        "cut",
   738→        "undo",
   739→        "redo",
   740→        "selectAll",
   741→        "save",
   742→        "quit",
   743→        "minimize",
   744→        "switchApp",
   745→        "newTab",
   746→        "closeTab",
   747→      ])
   748→      .describe("System command to execute"),
   749→  }),
   750→  execute: async ({ command }) => {
   751→    if (nutjsAvailable) {
   752→      const isMac = process.platform === "darwin";
   753→      const cmdKey = isMac ? Key.LeftSuper : Key.LeftControl;
   754→
   755→      switch (command) {
   756→        case "copy":
   757→          await keyboard.pressKey(cmdKey, Key.C);
   758→          await keyboard.releaseKey(cmdKey, Key.C);
   759→          return "Executed copy command";
   760→
   761→        case "paste":
   762→          await keyboard.pressKey(cmdKey, Key.V);
   763→          await keyboard.releaseKey(cmdKey, Key.V);
   764→          return "Executed paste command";
   765→
   766→        case "cut":
   767→          await keyboard.pressKey(cmdKey, Key.X);
   768→          await keyboard.releaseKey(cmdKey, Key.X);
   769→          return "Executed cut command";
   770→
   771→        case "undo":
   772→          await keyboard.pressKey(cmdKey, Key.Z);
   773→          await keyboard.releaseKey(cmdKey, Key.Z);
   774→          return "Executed undo command";
   775→
   776→        case "redo":
   777→          if (isMac) {
   778→            await keyboard.pressKey(cmdKey, Key.LeftShift, Key.Z);
   779→            await keyboard.releaseKey(cmdKey, Key.LeftShift, Key.Z);
   780→          } else {
   781→            await keyboard.pressKey(cmdKey, Key.Y);
   782→            await keyboard.releaseKey(cmdKey, Key.Y);
   783→          }
   784→          return "Executed redo command";
   785→
   786→        case "selectAll":
   787→          await keyboard.pressKey(cmdKey, Key.A);
   788→          await keyboard.releaseKey(cmdKey, Key.A);
   789→          return "Executed select all command";
   790→
   791→        case "save":
   792→          await keyboard.pressKey(cmdKey, Key.S);
   793→          await keyboard.releaseKey(cmdKey, Key.S);
   794→          return "Executed save command";
   795→
   796→        case "quit":
   797→          if (isMac) {
   798→            await keyboard.pressKey(cmdKey, Key.Q);
   799→            await keyboard.releaseKey(cmdKey, Key.Q);
   800→          } else {
   801→            await keyboard.pressKey(Key.LeftAlt, Key.F4);
   802→            await keyboard.releaseKey(Key.LeftAlt, Key.F4);
   803→          }
   804→          return "Executed quit command";
   805→
   806→        case "minimize":
   807→          if (isMac) {
   808→            await keyboard.pressKey(cmdKey, Key.M);
   809→            await keyboard.releaseKey(cmdKey, Key.M);
   810→          } else {
   811→            await keyboard.pressKey(Key.LeftSuper, Key.Down);
   812→            await keyboard.releaseKey(Key.LeftSuper, Key.Down);
   813→          }
   814→          return "Executed minimize command";
   815→
   816→        case "switchApp":
   817→          if (isMac) {
   818→            await keyboard.pressKey(cmdKey, Key.Tab);
   819→            await keyboard.releaseKey(cmdKey, Key.Tab);
   820→          } else {
   821→            await keyboard.pressKey(Key.LeftAlt, Key.Tab);
   822→            await keyboard.releaseKey(Key.LeftAlt, Key.Tab);
   823→          }
   824→          return "Executed switch app command";
   825→
   826→        case "newTab":
   827→          await keyboard.pressKey(cmdKey, Key.T);
   828→          await keyboard.releaseKey(cmdKey, Key.T);
   829→          return "Executed new tab command";
   830→
   831→        case "closeTab":
   832→          await keyboard.pressKey(cmdKey, Key.W);
   833→          await keyboard.releaseKey(cmdKey, Key.W);
   834→          return "Executed close tab command";
   835→
   836→        default:
   837→          throw new Error(`Unknown command: ${command}`);
   838→      }
   839→    } else {
   840→      // Fallback using AppleScript for macOS
   841→      const commandMap: { [key: string]: string } = {
   842→        copy: 'keystroke "c" using command down',
   843→        paste: 'keystroke "v" using command down',
   844→        cut: 'keystroke "x" using command down',
   845→        undo: 'keystroke "z" using command down',
   846→        redo: 'keystroke "z" using {command down, shift down}',
   847→        selectAll: 'keystroke "a" using command down',
   848→        save: 'keystroke "s" using command down',
   849→        quit: 'keystroke "q" using command down',
   850→        minimize: 'keystroke "m" using command down',
   851→        switchApp: "keystroke tab using command down",
   852→        newTab: 'keystroke "t" using command down',
   853→        closeTab: 'keystroke "w" using command down',
   854→      };
   855→
   856→      const script = commandMap[command];
   857→      if (script) {
   858→        child_process.execSync(
   859→          `osascript -e 'tell application "System Events" to ${script}'`
   860→        );
   861→        return `Executed ${command} command using AppleScript`;
   862→      } else {
   863→        throw new Error(`Unknown command: ${command}`);
   864→      }
   865→    }
   866→  },
   867→});
   868→
   869→// Parse command line arguments
   870→const args = process.argv.slice(2);
   871→const useStdio = args.includes("--stdio");
   872→const useHttp = args.includes("--sse") || !useStdio; // Default to HTTP/SSE if no flag specified
